# ─────────────────────────────────────────────────────────────────────────────

def print_step(n, msg):
    print(f"\n  [{n}] {msg}")

def make_dir(path):
    os.makedirs(path, exist_ok=True)

def write_file(path, content):
    os.makedirs(os.path.dirname(path) if os.path.dirname(path) else ".", exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)

def write_binary(path, b64_content):
    os.makedirs(os.path.dirname(path) if os.path.dirname(path) else ".", exist_ok=True)
    with open(path, "wb") as f:
        f.write(base64.b64decode(b64_content))

def main():
    print()
    print("╔══════════════════════════════════════════════════════════════╗")
    print("║   ADAPTIVE ENGINE - AUTOMATIC PROJECT SETUP                 ║")
    print("╚══════════════════════════════════════════════════════════════╝")
    print()
    print("  This will create the entire project structure for you.")
    print("  Sit back and watch! 🚀")

    # ── Step 1: Create all directories ───────────────────────────────────────
    print_step(1, "Creating folder structure...")
    dirs = [
        "app", "app/models", "app/routes",
        "app/services", "app/utils",
        "tests", "scripts", ".vscode",
    ]
    for d in dirs:
        make_dir(d)
        print(f"      📁 {d}/")
    print("      ✅ All folders created!")

    # ── Step 2: Write all source files ───────────────────────────────────────
    print_step(2, "Writing source files...")
    for path, b64 in FILES.items():
        write_binary(path, b64)
        size = os.path.getsize(path)
        print(f"      ✅ {path}  ({size:,} bytes)")

    # ── Step 3: VS Code config files ─────────────────────────────────────────
    print_step(3, "Writing VS Code configuration...")
    write_file(".vscode/settings.json", VSCODE_SETTINGS)
    print("      ✅ .vscode/settings.json  (Python interpreter + formatting)")
    write_file(".vscode/launch.json", VSCODE_LAUNCH)
    print("      ✅ .vscode/launch.json    (F5 = Run server, Tests, Setup checker)")
    write_file(".vscode/extensions.json", VSCODE_EXTENSIONS)
    print("      ✅ .vscode/extensions.json (Recommended extensions list)")

    # ── Step 4: REST Client test file ────────────────────────────────────────
    print_step(4, "Writing API test file for REST Client extension...")
    write_file("api_tests.http", API_HTTP)
    print("      ✅ api_tests.http  (Click 'Send Request' in VS Code to test)")

    # ── Step 5: Quick-start scripts ──────────────────────────────────────────
    print_step(5, "Writing platform quick-start scripts...")
    write_file("start.bat", WINDOWS_START)
    print("      ✅ start.bat       (Windows: double-click to start server)")
    write_file("start.sh", MAC_START)
    print("      ✅ start.sh        (Mac/Linux: bash start.sh)")
    # Make .sh executable on unix
    try:
        os.chmod("start.sh", 0o755)
    except Exception:
        pass

    # ── Step 6: Copy .env ────────────────────────────────────────────────────
    print_step(6, "Creating .env file from template...")
    if not os.path.exists(".env"):
        if os.path.exists(".env.example"):
            import shutil
            shutil.copy(".env.example", ".env")
            print("      ✅ .env created from .env.example")
    else:
        print("      ⏭️  .env already exists, skipping.")

    # ── Done ─────────────────────────────────────────────────────────────────
    print()
    print("  ╔══════════════════════════════════════════════════════════════╗")
    print("  ║  ✅  ALL FILES CREATED SUCCESSFULLY!                        ║")
    print("  ╠══════════════════════════════════════════════════════════════╣")
    print("  ║                                                              ║")
    print("  ║  NEXT STEPS:                                                 ║")
    print("  ║                                                              ║")
    print("  ║  1.  Create virtual environment:                             ║")

    if sys.platform == "win32":
        print("  ║      python -m venv venv                                    ║")
        print("  ║      venv\\\\Scripts\\\\activate                                 ║")
    else:
        print("  ║      python3 -m venv venv                                   ║")
        print("  ║      source venv/bin/activate                               ║")

    print("  ║                                                              ║")
    print("  ║  2.  Install dependencies:                                   ║")
    print("  ║      pip install -r requirements.txt                         ║")
    print("  ║                                                              ║")
    print("  ║  3.  Start the server:                                       ║")
    print("  ║      uvicorn app.main:app --reload --port 8000               ║")
    print("  ║      (or just press F5 in VS Code!)                          ║")
    print("  ║                                                              ║")
    print("  ║  4.  Open in browser:                                        ║")
    print("  ║      http://localhost:8000/docs                              ║")
    print("  ║                                                              ║")
    if sys.platform == "win32":
        print("  ║  💡 TIP: Double-click start.bat to do steps 1-3 at once!    ║")
    else:
        print("  ║  💡 TIP: Run  bash start.sh  to do steps 1-3 at once!       ║")
    print("  ║                                                              ║")
    print("  ╚══════════════════════════════════════════════════════════════╝")
    print()


if __name__ == "__main__":
    main()
